INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-00349', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式轉換型雙焦隱形眼鏡的敘述，下列何者錯誤？', '["視近區的位置及遠近帶的轉換是裝配成功的關鍵", "下眼瞼上緣的位置最好在角膜輪部下緣上下1mm以內的地方", "鏡片設計是上方看遠，下方看近，不受瞳孔大小影響，但是較小的瞳孔較難配，不利於視覺轉換", "它的設計，若驗配適當，遠近都清楚，不會影響對比敏感度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00350', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關非球面老花軟式隱形眼鏡的敘述，下列何者錯誤？', '["非球面的設計是鏡片屈光度由幾何中心向光學區的周邊逐步改變，鏡片中心為最大正值（最小負值）， 則為中心視近的設計（Center-neardesign）", "鏡片設計有中心視近（Center-neardesign）及中心視遠（Center-distancedesign）的設計，目前以前表面 非球面（Front-surfaceasphericdesign）中心視近區設計的軟式多焦隱形眼鏡最常被使用", "病人本身若眼球的正球面像差較大，則會增加中心視近設計鏡片的老花效果", "中心定位準確及鏡片較少滑動，可得到較好的視力表現，當鏡片中心偏位時，可能產生高階像差"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00351', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '硬式後表面非球面設計的鏡片，通常會比角膜曲率陡大約多少，以提供所需的光學效果及良好的定位？', '["0.2～0.4mm", "0.5～0.8mm", "0.9～1.2mm", "1.3～1.5mm"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00352', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '18年前曾經配戴過老花單眼視覺法（monovision）隱形眼鏡的患者，當時配戴得非常滿意，但在一次的眼 睛感染停止配戴後至今都沒有再戴過。現在希望重回老花單眼視覺法隱形眼鏡，但他喜歡閱讀（需+2.75D 的ADD）與常常使用電腦（+1.25D的ADD）。下列關於需要驗配的考量，何者正確？', '["過去的研究顯示，當近用度數需求越高時，單眼視覺法成功率越高", "當近用度數需求高過+2.50D時，在燈光較暗時的視力表現往往下降", "近用度數需求就算提高，立體視力（stereoacuity）一般來說不會有影響", "若近用度數需求高過+2.00D時，就算運用部分單眼視覺法（partialmonovision）亦沒有幫助"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00353', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '評估是否適合成為使用老花隱形眼鏡病患所需要做的初步評估，下列何者錯誤？', '["需評估病患瞳孔大小", "不需評估淚液的量和品質", "需測量優勢眼（dominanteye）", "需驗光且測量近距離與遠距離的最佳矯正視力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00354', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '若患者的驗光檢查結果為：OD：-3.25DS/-1.25DC 180；OS：-4.75DS/+1.75DC 090，則該名患者在未 經矯正下的視網膜成像應為何？', '["兩眼皆於視網膜前形成兩條焦線 × ×", "兩眼皆於視網膜後形成兩條焦線", "兩眼皆於視網膜前及視網膜後各形成一條焦線", "右眼於視網膜前形成兩條焦線，左眼於視網膜前及視網膜後各形成一條焦線"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00355', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於不等視（anisometropia）的敘述，下列何者錯誤？', '["不等視通過矯正眼鏡片當視線偏移雙眼鏡片光學中心激發稜鏡的差異", "不等視當使用眼鏡矯正對雙眼間有不同的調節刺激", "不等視當使用眼鏡矯正造成雙眼眼鏡放大率的差異", "先天性青光眼，先天性白內障和先天性第三神經麻痺等不會造成遺傳性不等視"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00356', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '當調節完全放鬆，患者此時可看到最清楚的點，稱為下列何者？', '["遠點（far-point）", "近點（near-point）", "調節幅度（accommodativeamplitude）", "調節範圍（rangeofaccommodation）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00357', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列有關夜間近視之敘述，何者錯誤？', '["可能為夜間低光源照射下，對於眼睛調節的刺激不足所致", "低光源導致瞳孔放大，引起球面像差增加", "低度遠視的患者若有夜間近視情況，在配戴原有矯正處方於夜間用眼時，會感到比白天還要更清晰", "一般情況下，夜間近視約為增加-0.50～-1.00D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00358', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關對比敏感度檢查Marstest之敘述，下列何者錯誤？', '["視標尺寸為23 35.5cm", "檢測時，患者與視標間之測試距離為1m", "每一個視標大小×為6/144", "視標維持每行6個字元，共計8行，字元間以0.04logunit逐漸遞減對比度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
